/**
 * Webhook Manager Component
 * 
 * Allows vendors to configure webhook endpoints for receiving event notifications:
 * - Credential issuance events
 * - Verification events
 * - Application status changes
 * - Trust framework updates
 */

import React, { useState, useEffect } from 'react';
import {
  Box,
  Paper,
  Typography,
  Button,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  IconButton,
  Chip,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  FormControl,
  FormLabel,
  FormGroup,
  FormControlLabel,
  Checkbox,
  Alert,
  CircularProgress,
  Tooltip,
} from '@mui/material';
import AddIcon from '@mui/icons-material/Add';
import DeleteIcon from '@mui/icons-material/Delete';
import EditIcon from '@mui/icons-material/Edit';
import WebhookIcon from '@mui/icons-material/Webhook';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import ErrorIcon from '@mui/icons-material/Error';
import RefreshIcon from '@mui/icons-material/Refresh';

const API_BASE_URL = process.env.REACT_APP_API_BASE_URL || '';

/**
 * Available webhook event types
 */
const EVENT_TYPES = [
  { id: 'credential.issued', label: 'Credential Issued', description: 'Triggered when a credential is issued' },
  { id: 'credential.revoked', label: 'Credential Revoked', description: 'Triggered when a credential is revoked' },
  { id: 'verification.completed', label: 'Verification Completed', description: 'Triggered when a verification is completed' },
  { id: 'verification.failed', label: 'Verification Failed', description: 'Triggered when a verification fails' },
  { id: 'application.submitted', label: 'Application Submitted', description: 'Triggered when an applicant submits an application' },
  { id: 'application.approved', label: 'Application Approved', description: 'Triggered when an application is approved' },
  { id: 'application.rejected', label: 'Application Rejected', description: 'Triggered when an application is rejected' },
  { id: 'trust.updated', label: 'Trust Framework Updated', description: 'Triggered when trust settings change' },
];

/**
 * Webhook Manager Component
 */
export default function WebhookManager() {
  const [webhooks, setWebhooks] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [dialogOpen, setDialogOpen] = useState(false);
  const [editingWebhook, setEditingWebhook] = useState(null);

  // Form state
  const [url, setUrl] = useState('');
  const [description, setDescription] = useState('');
  const [selectedEvents, setSelectedEvents] = useState([]);
  const [secret, setSecret] = useState('');
  const [saving, setSaving] = useState(false);

  // Load webhooks on mount
  useEffect(() => {
    loadWebhooks();
  }, []);

  const loadWebhooks = async () => {
    setLoading(true);
    setError(null);

    try {
      // TODO: Replace with actual API call when backend is ready
      // Mock data for now
      setTimeout(() => {
        setWebhooks([
          {
            id: '1',
            url: 'https://example.com/webhooks/marty',
            description: 'Production webhook endpoint',
            events: ['credential.issued', 'verification.completed'],
            active: true,
            created_at: '2026-01-15T10:30:00Z',
            last_triggered: '2026-01-18T09:15:00Z',
          },
        ]);
        setLoading(false);
      }, 500);
    } catch (err) {
      setError(err.message);
      setLoading(false);
    }
  };

  const handleOpenDialog = (webhook = null) => {
    if (webhook) {
      setEditingWebhook(webhook);
      setUrl(webhook.url);
      setDescription(webhook.description);
      setSelectedEvents(webhook.events);
      setSecret('');
    } else {
      setEditingWebhook(null);
      setUrl('');
      setDescription('');
      setSelectedEvents([]);
      setSecret('');
    }
    setDialogOpen(true);
  };

  const handleCloseDialog = () => {
    setDialogOpen(false);
    setEditingWebhook(null);
  };

  const handleEventToggle = (eventId) => {
    setSelectedEvents((prev) =>
      prev.includes(eventId)
        ? prev.filter((id) => id !== eventId)
        : [...prev, eventId]
    );
  };

  const handleSave = async () => {
    if (!url.trim()) {
      setError('URL is required');
      return;
    }

    if (selectedEvents.length === 0) {
      setError('Select at least one event type');
      return;
    }

    setSaving(true);
    setError(null);

    try {
      // TODO: Replace with actual API call when backend is ready
      /*
      const webhookData = {
        url: url.trim(),
        description: description.trim(),
        events: selectedEvents,
        secret: secret.trim() || undefined,
      };

      const response = await fetch(
        editingWebhook
          ? `${API_BASE_URL}/api/webhooks/${editingWebhook.id}`
          : `${API_BASE_URL}/api/webhooks`,
        {
          method: editingWebhook ? 'PUT' : 'POST',
          headers: { 'Content-Type': 'application/json' },
          credentials: 'include',
          body: JSON.stringify(webhookData),
        }
      );

      if (!response.ok) {
        const data = await response.json();
        throw new Error(data.detail || 'Failed to save webhook');
      }
      */

      // Mock success
      setTimeout(() => {
        loadWebhooks();
        handleCloseDialog();
        setSaving(false);
      }, 500);
    } catch (err) {
      setError(err.message);
      setSaving(false);
    }
  };

  const handleDelete = async (webhookId) => {
    if (!window.confirm('Are you sure you want to delete this webhook?')) {
      return;
    }

    try {
      // TODO: Replace with actual API call when backend is ready
      /*
      const response = await fetch(`${API_BASE_URL}/api/webhooks/${webhookId}`, {
        method: 'DELETE',
        credentials: 'include',
      });

      if (!response.ok) {
        const data = await response.json();
        throw new Error(data.detail || 'Failed to delete webhook');
      }
      */

      // Mock success
      setTimeout(() => {
        loadWebhooks();
      }, 500);
    } catch (err) {
      setError(err.message);
    }
  };

  const handleTest = async (webhookId) => {
    try {
      // TODO: Replace with actual API call when backend is ready
      /*
      const response = await fetch(`${API_BASE_URL}/api/webhooks/${webhookId}/test`, {
        method: 'POST',
        credentials: 'include',
      });

      if (!response.ok) {
        const data = await response.json();
        throw new Error(data.detail || 'Failed to test webhook');
      }
      */

      alert('Test event sent successfully!');
    } catch (err) {
      setError(err.message);
    }
  };

  if (loading) {
    return (
      <Box sx={{ display: 'flex', justifyContent: 'center', p: 4 }}>
        <CircularProgress />
      </Box>
    );
  }

  return (
    <Box data-testid="webhook-manager">
      {/* Header */}
      <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 3 }}>
        <Box>
          <Typography variant="h6" gutterBottom>
            Webhook Endpoints
          </Typography>
          <Typography variant="body2" color="text.secondary">
            Configure endpoints to receive real-time event notifications from Marty
          </Typography>
        </Box>
        <Button
          variant="contained"
          startIcon={<AddIcon />}
          onClick={() => handleOpenDialog()}
        >
          Add Webhook
        </Button>
      </Box>

      {/* Error Alert */}
      {error && (
        <Alert severity="error" onClose={() => setError(null)} sx={{ mb: 3 }}>
          {error}
        </Alert>
      )}

      {/* Info Alert */}
      <Alert severity="info" sx={{ mb: 3 }}>
        <Typography variant="body2">
          Webhooks allow your application to receive real-time notifications about events in Marty.
          Each webhook will receive a POST request with event data and a signature for verification.
        </Typography>
      </Alert>

      {/* Webhooks Table */}
      {webhooks.length === 0 ? (
        <Paper sx={{ p: 4, textAlign: 'center', bgcolor: 'grey.50' }}>
          <WebhookIcon sx={{ fontSize: 60, color: 'text.secondary', mb: 2 }} />
          <Typography variant="h6" gutterBottom>
            No Webhooks Configured
          </Typography>
          <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
            Add a webhook endpoint to start receiving event notifications
          </Typography>
          <Button variant="contained" startIcon={<AddIcon />} onClick={() => handleOpenDialog()}>
            Add Your First Webhook
          </Button>
        </Paper>
      ) : (
        <TableContainer component={Paper}>
          <Table>
            <TableHead>
              <TableRow>
                <TableCell>URL</TableCell>
                <TableCell>Description</TableCell>
                <TableCell>Events</TableCell>
                <TableCell>Status</TableCell>
                <TableCell>Last Triggered</TableCell>
                <TableCell align="right">Actions</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {webhooks.map((webhook) => (
                <TableRow key={webhook.id}>
                  <TableCell>
                    <Typography variant="body2" sx={{ fontFamily: 'monospace' }}>
                      {webhook.url}
                    </Typography>
                  </TableCell>
                  <TableCell>{webhook.description}</TableCell>
                  <TableCell>
                    <Box sx={{ display: 'flex', gap: 0.5, flexWrap: 'wrap' }}>
                      {webhook.events.slice(0, 2).map((event) => (
                        <Chip key={event} label={event} size="small" />
                      ))}
                      {webhook.events.length > 2 && (
                        <Chip label={`+${webhook.events.length - 2}`} size="small" variant="outlined" />
                      )}
                    </Box>
                  </TableCell>
                  <TableCell>
                    {webhook.active ? (
                      <Chip
                        icon={<CheckCircleIcon />}
                        label="Active"
                        color="success"
                        size="small"
                      />
                    ) : (
                      <Chip
                        icon={<ErrorIcon />}
                        label="Inactive"
                        color="error"
                        size="small"
                      />
                    )}
                  </TableCell>
                  <TableCell>
                    {webhook.last_triggered
                      ? new Date(webhook.last_triggered).toLocaleString()
                      : 'Never'}
                  </TableCell>
                  <TableCell align="right">
                    <Tooltip title="Test webhook">
                      <IconButton size="small" onClick={() => handleTest(webhook.id)}>
                        <RefreshIcon />
                      </IconButton>
                    </Tooltip>
                    <Tooltip title="Edit webhook">
                      <IconButton size="small" onClick={() => handleOpenDialog(webhook)}>
                        <EditIcon />
                      </IconButton>
                    </Tooltip>
                    <Tooltip title="Delete webhook">
                      <IconButton size="small" onClick={() => handleDelete(webhook.id)}>
                        <DeleteIcon />
                      </IconButton>
                    </Tooltip>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </TableContainer>
      )}

      {/* Add/Edit Dialog */}
      <Dialog open={dialogOpen} onClose={handleCloseDialog} maxWidth="md" fullWidth>
        <DialogTitle>
          {editingWebhook ? 'Edit Webhook' : 'Add Webhook'}
        </DialogTitle>
        <DialogContent>
          <Box sx={{ pt: 2 }}>
            <TextField
              label="Webhook URL"
              fullWidth
              value={url}
              onChange={(e) => setUrl(e.target.value)}
              placeholder="https://your-domain.com/webhooks/marty"
              helperText="The endpoint that will receive POST requests with event data"
              sx={{ mb: 3 }}
              required
            />

            <TextField
              label="Description"
              fullWidth
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              placeholder="Production webhook endpoint"
              helperText="Optional description to help identify this webhook"
              sx={{ mb: 3 }}
            />

            <FormControl component="fieldset" sx={{ mb: 3 }}>
              <FormLabel component="legend">Event Types *</FormLabel>
              <Typography variant="caption" color="text.secondary" sx={{ mb: 1 }}>
                Select which events should trigger this webhook
              </Typography>
              <FormGroup>
                {EVENT_TYPES.map((eventType) => (
                  <FormControlLabel
                    key={eventType.id}
                    control={
                      <Checkbox
                        checked={selectedEvents.includes(eventType.id)}
                        onChange={() => handleEventToggle(eventType.id)}
                      />
                    }
                    label={
                      <Box>
                        <Typography variant="body2">{eventType.label}</Typography>
                        <Typography variant="caption" color="text.secondary">
                          {eventType.description}
                        </Typography>
                      </Box>
                    }
                  />
                ))}
              </FormGroup>
            </FormControl>

            <TextField
              label="Webhook Secret (Optional)"
              fullWidth
              value={secret}
              onChange={(e) => setSecret(e.target.value)}
              type="password"
              placeholder="Enter a secret for signature verification"
              helperText="Used to generate HMAC signatures for verifying webhook authenticity"
            />
          </Box>
        </DialogContent>
        <DialogActions>
          <Button onClick={handleCloseDialog}>Cancel</Button>
          <Button
            onClick={handleSave}
            variant="contained"
            disabled={saving || !url.trim() || selectedEvents.length === 0}
          >
            {saving ? 'Saving...' : editingWebhook ? 'Update' : 'Create'}
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
}
